import type { ListPaginationItem, ListPaginationViewItem } from 'lyrixi-mobile'

// \u5C06\u5217\u8868\u6570\u636E\u6309\u7167 anchor \u5B57\u6BB5\u5206\u7EC4
function formatViewList(list: ListPaginationItem[]): ListPaginationViewItem[] {
  if (!Array.isArray(list) || list.length === 0) {
    return []
  }

  // \u4F7F\u7528 Map \u6765\u6309 anchor \u5206\u7EC4\uFF08\u5206\u7EC4\u5934\u4E5F\u662F ListViewItem\uFF1A\u5FC5\u542B _raw\u3001id\uFF09
  const groupMap = new Map<string, ListPaginationViewItem>()

  list.forEach((raw) => {
    const item = raw as Record<string, unknown>
    const anchor = item.anchor as string | undefined
    if (anchor) {
      if (!groupMap.has(anchor)) {
        groupMap.set(anchor, {
          _raw: {} as ListPaginationItem,
          id: anchor,
          title: anchor,
          anchor: anchor,
          children: []
        })
      }
      const group = groupMap.get(anchor)
      if (!group?.children) return
      group.children.push({
        // \u539F\u59CB\u884C\u5F15\u7528\uFF08\u4E0E \`list\` \u4E2D\u9879\u5BF9\u5E94\uFF1B\u5206\u7EC4\u540E\u987A\u5E8F\u53D8\u5316\u65F6\u7531\u4E1A\u52A1\u4FDD\u8BC1 _raw\uFF09
        _raw: item,
        // \u552F\u4E00\u6807\u8BC6(\u5FC5\u4F20)
        id: item.id,
        // \u5DE6\u4FA7\u56FE\u7247
        imageUrl: String(item.imageUrl ?? ''),
        // \u5934\u50CF
        avatarUrl: String(item.avatarUrl ?? ''),
        // \u7B2C\u4E00\u884C\u6587\u5B57
        title: item.name,
        // \u7B2C\u4E8C\u884C\u6587\u5B57
        description: item.introduce,
        // \u7B2C\u4E00\u884C\u53F3\u4E0A\u89D2\u6587\u5B57
        note: item.note,
        // \u7B2C\u4E09\u884C\u6587\u5B57
        content: item.content,
        // \u53F3\u4FA7\u64CD\u4F5C\u6309\u94AE
        actionRender: (row: ListPaginationItem & { checked?: boolean }) => {
          const name = row.name
          return <div>Click {name as ReactNode}</div>
        }
      })
    }
  })

  // \u5C06 Map \u8F6C\u6362\u4E3A\u6570\u7EC4\uFF0C\u5E76\u6309 anchor \u5B57\u6BCD\u987A\u5E8F\u6392\u5E8F
  return Array.from(groupMap.values()).sort((a, b) => {
    return String(a.anchor ?? '').localeCompare(String(b.anchor ?? ''))
  })
}

export default formatViewList
